import { AppCompatActivityAdapter, ActivityState } from './coding';
import { BundleAdapter } from '../16.1.20-BUNDLE-ADAPTER/coding';

// Mock implementation for testing
class TestActivity extends AppCompatActivityAdapter {
  onCreateCalled = false;
  onStartCalled = false;
  onResumeCalled = false;
  onPauseCalled = false;
  onStopCalled = false;
  onDestroyCalled = false;
  savedState: BundleAdapter | null = null;
  
  protected onCreate(savedInstanceState: BundleAdapter): void {
    this.onCreateCalled = true;
    this.savedState = savedInstanceState;
  }
  
  protected onStart(): void {
    this.onStartCalled = true;
  }
  
  protected onResume(): void {
    this.onResumeCalled = true;
  }
  
  protected onPause(): void {
    this.onPauseCalled = true;
  }
  
  protected onStop(): void {
    this.onStopCalled = true;
  }
  
  protected onDestroy(): void {
    this.onDestroyCalled = true;
  }
}

describe('AppCompatActivityAdapter', () => {
  let activity: TestActivity;

  beforeEach(() => {
    activity = new TestActivity();
  });

  describe('Lifecycle - Creation', () => {
    test('should start in CREATED state', () => {
      expect(activity.getState()).toBe(ActivityState.CREATED);
    });

    test('should call onCreate when page shows', () => {
      activity.onPageShow();
      expect(activity.onCreateCalled).toBe(true);
    });

    test('should pass savedInstanceState to onCreate', () => {
      activity.onPageShow();
      expect(activity.savedState).toBeInstanceOf(BundleAdapter);
    });
  });

  describe('Lifecycle - Start/Resume', () => {
    test('should call onStart when page shows', () => {
      activity.onPageShow();
      expect(activity.onStartCalled).toBe(true);
    });

    test('should call onResume when page shows', () => {
      activity.onPageShow();
      expect(activity.onResumeCalled).toBe(true);
    });

    test('should be in RESUMED state after page show', () => {
      activity.onPageShow();
      expect(activity.getState()).toBe(ActivityState.RESUMED);
    });
  });

  describe('Lifecycle - Pause/Stop', () => {
    test('should call onPause when page hides', () => {
      activity.onPageShow();
      activity.onPageHide();
      expect(activity.onPauseCalled).toBe(true);
    });

    test('should call onStop when page hides', () => {
      activity.onPageShow();
      activity.onPageHide();
      expect(activity.onStopCalled).toBe(true);
    });

    test('should be in STOPPED state after page hide', () => {
      activity.onPageShow();
      activity.onPageHide();
      expect(activity.getState()).toBe(ActivityState.STOPPED);
    });
  });

  describe('Lifecycle - Destroy', () => {
    test('should call onDestroy when finished', () => {
      activity.onPageShow();
      activity.finish();
      expect(activity.onDestroyCalled).toBe(true);
    });

    test('should be in DESTROYED state after finish', () => {
      activity.onPageShow();
      activity.finish();
      expect(activity.getState()).toBe(ActivityState.DESTROYED);
    });

    test('should return true for isFinishing when destroyed', () => {
      activity.onPageShow();
      activity.finish();
      expect(activity.isFinishing()).toBe(true);
    });
  });

  describe('State Management', () => {
    test('should save instance state on page hide', () => {
      activity.onPageShow();
      activity.onPageHide();
      expect(activity.savedState).toBeInstanceOf(BundleAdapter);
    });

    test('should restore saved state on recreate', () => {
      // First show
      activity.onPageShow();
      
      // Hide (saves state)
      activity.onPageHide();
      
      // Create new activity with saved state
      const newActivity = new TestActivity();
      newActivity.savedInstanceState = activity.savedState!;
      newActivity.onPageShow();
      
      expect(newActivity.savedState).toBe(activity.savedState);
    });
  });

  describe('Content View', () => {
    test('should set content view by layout ID', () => {
      activity.setContentView(12345);
      // Internal state should be set
      expect(activity['contentView']).toEqual({ layoutId: 12345 });
    });

    test('should set content view with view object', () => {
      const mockView = { type: 'View' };
      activity.setContentViewWithView(mockView);
      expect(activity['contentView']).toBe(mockView);
    });
  });

  describe('Page Destroy', () => {
    test('should destroy activity on page destroy', () => {
      activity.onPageShow();
      activity.onPageDestroy();
      expect(activity.onDestroyCalled).toBe(true);
      expect(activity.getState()).toBe(ActivityState.DESTROYED);
    });

    test('should handle double destroy gracefully', () => {
      activity.onPageShow();
      activity.onPageDestroy();
      activity.onPageDestroy(); // Should not throw
      expect(activity.getState()).toBe(ActivityState.DESTROYED);
    });
  });
});

